1	interface Item {
2	  name: string;
3	  type: "standard" | "component";
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	interface QuoteOptions {
9	  insurance?: boolean;
10	  years?: number;
11	  followUp?: boolean;
12	  fiveG?: boolean;
13	}
14	
15	const getBaseCostByType = (itemType: string): number => {
16	  return itemType === "component" ? 5 : 10;
17	};
18	
19	const calculateItemPremium = (item: Item): number => {
20	  let premium = getBaseCostByType(item.type);
21	  if (item.cursed) {
22	    premium += premium * 0.5;
23	  }
24	  if (item.enchantment !== undefined && item.enchantment >= 5) {
25	    premium += premium * 0.3;
26	  }
27	  return premium;
28	};
29	
30	const applyModifier = (amount: number, multiplier: number): number => {
31	  return amount + amount * multiplier;
32	};
33	
34	const applyConditionalModifier = (
35	  amount: number,
36	  condition: boolean,
37	  multiplier: number
38	): number => {
39	  return condition ? applyModifier(amount, multiplier) : amount;
40	};
41	
42	export function quote(items: Item[], options: QuoteOptions = {}): number {
43	  let total = 0;
44	  for (const item of items) {
45	    total += calculateItemPremium(item);
46	  }
47	  total = applyConditionalModifier(total, options.insurance === true, 0.1);
48	  total = applyConditionalModifier(
49	    total,
50	    options.years !== undefined && options.years >= 2,
51	    -0.2
52	  );
53	  total = applyConditionalModifier(total, options.followUp === true, -0.15);
54	  return total;
55	}
